import { useEffect, useState } from "react"

const paymentPlans = [{
    planTitle: '24x',
    planDuration: '24',
    planTag: 'Bestseller',
    id: 'plan-1'
},
{
    planTitle: '12x',
    planDuration: '12',
    planTag: 'Most Popular',
    id: 'plan-2'
},
{
    planTitle: '6x',
    planDuration: '6',
    planTag: 'Balanced',
    id: 'plan-3'
},
{
    planTitle: '3x',
    planDuration: '3',
    planTag: 'Quick Pay',
    id: 'plan-4'
}
]

async function calculateInstallments(totalAmount, activePlan) {
    const startDate = new Date()
    const data = await new Promise((res) => {
        const { planDuration } = activePlan

        const arr = getCalculatedInstallments(totalAmount, activePlan)
        setTimeout(() => {
            res([...arr])
        }, 1000)
    })
    return data
}
export async function getPlansData() {
    return new Promise((resolve, reject) => {
        setTimeout(() => {
            return resolve(paymentPlans)
        }, 500)
    })
}

export async function getInstallments(totalAmount, activePlan) {
    return new Promise((resolve, reject) => {
        setTimeout(() => {
            return resolve(calculateInstallments(totalAmount, activePlan))
        }, 500)
    })
}

function useData(fn, options = { loadOnRefetch: false }) {
    const [resp, setResp] = useState({
        data: null,
        loading: false,
        error: null
    })

    async function fetchData(fn) {
        setResp((prev) => {
            return {
                ...prev,
                loading: true
            }
        })
        try {
            const result = await fn()
            setResp((prev) => {
                return {
                    ...prev,
                    data: result
                }
            })
        } catch (err) {
            setResp((prev) => {
                return {
                    ...prev,
                    error: { message: 'Following error occured:', log: err }
                }
            })
        } finally {
            setResp((prev) => {
                return {
                    ...prev,
                    loading: false
                }
            })
        }
    }

    function refetch(...args) {
        fetchData(...args)
    }

    useEffect(() => {
        if (!options.loadOnRefetch && fn) {
            fetchData(fn)
        }
    }, [])

    return { refetch, ...resp }
}

export default useData
